import { products } from "../data.js";
import type { Product } from "../types.js";

export interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

export interface ProductSummary {
  count: number;
  totalInventoryValue: number;
  averagePrice: number;
}

export interface ProductListResult {
  products: Product[];
  summary: ProductSummary;
}

export interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export type ServiceResult<T> =
  | { ok: true; data: T }
  | { ok: false; error: string; code: "not_found" | "bad_request" };

export function listProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProductById(id: number): ServiceResult<ProductDetail> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { ok: false, error: "Product not found", code: "not_found" };
  }

  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;

  return {
    ok: true,
    data: {
      ...product,
      isLowStock,
      inventoryValue,
    },
  };
}

export function adjustStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetail> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { ok: false, error: "Product not found", code: "not_found" };
  }

  if (typeof adjustment !== "number") {
    return { ok: false, error: "adjustment must be a number", code: "bad_request" };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { ok: false, error: "Insufficient stock", code: "bad_request" };
  }

  product.stock = newStock;

  return {
    ok: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem, CreateOrderInput } from "../types.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface OrderSummary {
  count: number;
  totalRevenue: number;
}

export interface OrderListResult {
  orders: Order[];
  summary: OrderSummary;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export type ServiceResult<T> =
  | { ok: true; data: T }
  | { ok: false; error: string; code: "not_found" | "bad_request" };

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): ServiceResult<EnrichedOrder> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { ok: false, error: "Order not found", code: "not_found" };
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ok: true,
    data: {
      ...order,
      items: enrichedItems,
    },
  };
}

export function createOrder(input: CreateOrderInput): ServiceResult<Order> {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return { ok: false, error: "userId and items are required", code: "bad_request" };
  }

  if (input.items.length === 0) {
    return {
      ok: false,
      error: "Order must have at least one item",
      code: "bad_request",
    };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return {
        ok: false,
        error: `Product ${item.productId} not found`,
        code: "bad_request",
      };
    }

    if (item.quantity <= 0) {
      return {
        ok: false,
        error: "Quantity must be positive",
        code: "bad_request",
      };
    }

    if (product.stock < item.quantity) {
      return {
        ok: false,
        error: `Insufficient stock for ${product.name}`,
        code: "bad_request",
      };
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { ok: true, data: order };
}

export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { ok: false, error: "Order not found", code: "not_found" };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    return {
      ok: false,
      error: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      code: "bad_request",
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      ok: false,
      error: `Cannot transition from ${order.status} to ${status}`,
      code: "bad_request",
    };
  }

  order.status = status as typeof order.status;

  return { ok: true, data: order };
}

